mapper.select:
SELECT DISTINCT rec.competition_id
FROM external_competition_record rec
         LEFT JOIN external_competition com ON com.id = rec.competition_id
WHERE rec.deleted = 0
  AND com.deleted = 0

    AND com.school_id = #{reqModel.schoolId}


    AND com.school_year = #{reqModel.schoolYear}


    AND rec.class_id = #{reqModel.classId}


    AND rec.student_id = #{reqModel.studentId}

SELECT student_id AS studentId, COUNT(*) AS count
FROM external_competition_record
WHERE update_time >= #{semesterStart}
  AND #{semesterEnd} >= update_time
  AND class_id = #{classId}
GROUP BY student_id
